import{_ as t}from"./plugin-vue_export-helper.21dcd24c.js";import{o as r,b as a,ac as c}from"./framework.4684342f.js";const g='{"title":"2018.04.02 \u5982\u9D3F\u7684\u884C\u677F","description":"","frontmatter":{"title":"2018.04.02 \u5982\u9D3F\u7684\u884C\u677F","date":"2018-04-02T09:24:01.000Z","categories":["\u751F\u6D3B\u8A18\u4E8B"]},"headers":[],"relativePath":"Bike/BikeTravel/20180402_\u5982\u9D3F\u7684\u884C\u677F.md","lastUpdated":1679296000872}',s={},e=c('<p><img src="https://farm1.staticflickr.com/869/39417835340_358f70d862.jpg" alt=""><br> \u9031\u4E00\u5728\u4E0B\u73ED\u56DE\u5BB6\u7684\u6642<br> \u5728\u67D0\u500B\u4E09\u53C9\u8DEF\u53E3\u8F49\u5F4E\u8655\u649E\u5230\u9D3F\u5B50<br> \u5C0D\uFF0C\u5C31\u662F\u5728\u5929\u4E0A\u98DB\u7684\u9D3F\u5B50<br></p><p>\u539F\u672C\u5728\u9583\u8EB2\u8DEF\u9762\u7684\u5751\u6D1E<br> \u7A81\u7136\u6709\u500B\u7070\u8272\u7269\u9AD4\u8DF3\u52D5<br> \u8981\u9583\u7684\u6642\u5019\u4F86\u4E0D\u53CA\u4E86\uFF0C\u5C31\u6E1B\u901F\u8FCE\u9762\u649E\u4E0A\u53BB<br> \u5F8C\u4F86\u7336\u8C6B\u8981\u4E0D\u8981\u505C\u4E0B\u4F86\u770B<br> \u56DE\u982D\u770B\u4E00\u4E0B\uFF0C\u9D3F\u5B50\u9084\u5728\u52D5<br> \u5C31\u56DE\u982D\u628A\u9D3F\u5B50\u8F09\u56DE\u5BB6\u7D66\u8001\u7238\u770B<br><img src="https://farm1.staticflickr.com/870/26354859077_35a8559e24.jpg" alt=""><br><img src="https://farm1.staticflickr.com/822/26354851927_dac39bddc1.jpg" alt=""><br><img src="https://farm1.staticflickr.com/886/26354843257_23e6a38d38.jpg" alt=""><br><img src="https://farm1.staticflickr.com/806/27353795128_408a9ee968.jpg" alt=""></p><p>\u770B\u4E86\u4E00\u4E0B\uFF0C\u9D3F\u5B50\u5DE6\u534A\u908A\u5728\u6D41\u8840<br> \u4F46\u9D3F\u5B50\u5F9E\u982D\u5230\u5C3E\u90FD\u6C92\u6709\u51FA\u8072<br> \u8001\u7238\u8AAA\uFF0C\u9019\u662F\u96BB\u5E7C\u5E74\u8CFD\u9D3F<br> \u50B7\u6210\u9019\u6A23\uFF0C\u4E5F\u61C9\u8A72\u6D3B\u4E0D\u4E86\u4E86<br> \u5F8C\u4F86\u5C31\u8F09\u53BB\u91CE\u5916\u653E\u751F</p><p>\u5F8C\u7E8C\u770B\u5230\uFF0C\u8CFD\u9D3F\u539F\u4F86\u5728\u53F0\u7063\u883B\u71B1\u9580\u7684<br> \u5357\u81FA\u7063\u883B\u591A\u4F4F\u6236\u9802\u6A13\u90FD\u52A0\u84CB\u9D3F\u820D<br> \u8CFD\u9D3F\u4E5F\u883B\u6B98\u5FCD\u7684\uFF0C\u6BD4\u8CFD\u8DDD\u96E2\u6703\u8D8A\u4F86\u8D8A\u9577<br> \u5F9E\u4EE5\u524D\u7684\u9678\u5730\u5230\u73FE\u5728\u7684\u6D77\u9762<br> \u9D3F\u5B50\u8981\u5F9E\u9577\u8DDD\u96E2\u7684\u8CFD\u7A0B\u4E2D\u5B58\u6D3B\u662F\u4E0D\u5BB9\u6613\u7684<br> \u5C31\u7B97\u6D3B\u4E0B\u4F86\uFF0C\u6BD4\u5B8C\u8CFD\u5F8C\u6700\u5F8C\u7684\u4E0B\u843D\u4E5F\u4E0D\u77E5\u5982\u4F55</p><p>\u6700\u5F8C\u653E\u5E7E\u5F35\u4ECA\u5929\u53BB\u770B\u4EBA\u5BB6\u653E\u9D3F\u8A13\u7DF4\u7684\u7167\u7247<br> \u5E0C\u671B\u9019\u4E9B\u9D3F\u5B50\u90FD\u80FD\u5728\u6BD4\u8CFD\u4E2D\u9806\u5229\u56DE\u5BB6~<br><img src="https://farm1.staticflickr.com/870/40330610135_365f4624d7.jpg" alt=""><img src="https://farm1.staticflickr.com/821/39417305520_4ef433f1dd.jpg" alt=""><br><img src="https://farm1.staticflickr.com/809/39417300380_a3e05bd16d.jpg" alt=""><br><img src="https://farm1.staticflickr.com/803/40330584505_0fe2a3ab5a.jpg" alt=""><br><img src="https://farm1.staticflickr.com/891/41183052092_886b271b83.jpg" alt=""></p><p>\u4EE5\u4E0B\u5F15\u7528\u8AD6\u6587<br><a href="https://ndltd.ncl.edu.tw/cgi-bin/gs32/gsweb.cgi?o=dnclcdr&amp;s=id=%22101NHU05665001%22.&amp;searchmode=basic&amp;extralimit=asc=%22%E5%8D%97%E8%8F%AF%E5%A4%A7%E5%AD%B8%22&amp;extralimitunit=%E5%8D%97%E8%8F%AF%E5%A4%A7%E5%AD%B8" target="_blank" rel="noopener noreferrer">\u53F0\u7063\u8CFD\u9D3F\u7684\u793E\u6703\u5B78\u5206\u6790Sociological Analysis of pigeon racing in Taiwan</a></p><blockquote><p><span style="color:red;">\u5982\u679C\u5C0D\u4EBA\uF92D\uF96F\uFF0C\u8CFD\u9D3F\u8F38\u6389\u7684\u6642\u5019\uFF0C\u8F38\u6389\u7684\u662F\uF90A\u9322\uFF0C\u4F46\u662F\u5C0D\u9D3F\u5B50\uF92D\uF96F\uFF0C\u7260\u8F38\u6389\u7684\u78BA\u662F\u751F\u547D\u3002</span><br> \u9D3F\u5B50\u5F9E\u51FA\u751F\u5230\u8A13\uF996\uFF0C\u4E00\u76F4\u5230\u6BD4\u8CFD\uFF0C\u9019\u662F\u4E00\u5834\u5F88\u8271\u8F9B\u7684\u6311\u6230\uFF0C<br> \u4E00\u6279\u9D3F\u5B50\u51FA\uF92D\uFF0C<span style="color:blue;">\u4E00\u958B\u59CB\u53EF\u80FD\u6709 20-30 \u96BB\uFF0C\u7136\u800C\u6700\u5F8C\u5269\u4E0B\u7684\u5462\uFF1F<br> \u5C48\u6307\u53EF\uF969\u5427\uFF01\u6709\u7684\u5F9E\u51FA\u751F\u56E0\u70BA\u67D3\u75C5\u800C\uF967\u5E78\u904E\u4E16\uFF0C\u800C\u6709\u7684\u78BA\u662F\u5728\u8A13\uF996\u53CA\u6BD4\u8CFD\u4E2D\u6D88\u901D\uFF0C<br> \u4F46\u80FD\u5920\u5B58\u6D3B\u4E0B\uF92D\u7684\uFF0C\u4E5F\u6709\u53EF\u80FD\u4EE5\u6210\u7E3E\u7684\uF967\uF9E4\u60F3\uFF0C\u800C\u62DB\u81F4\u6BC0\u6EC5\uFF0C<br> \u9019\u5728\u81EA\u7136\u754C\u5C31\u597D\u50CF\u9054\u723E\u6587\u6240\uF96F\u7684\uFF1A\u5F31\u8089\u5F37\u98DF\u3001\u9069\u8005\u751F\u5B58\u3002</span></p></blockquote><blockquote><p><span style="color:red;">\u4E00\u500B\u9D3F\u5B50\u8981\u98DB\u5F97\u597D\uFF0C\u9664\uF9BA\u54C1\u7A2E\u4EE5\u5916\uFF0C\u6700\u91CD\u8981\u7684\u5C31\u662F\u8A13\uF996\uF9BA\uFF0C\uF967\uF941\u5728\u5E73\u6642\u7684\u653E\u98DB\u6216\u662F\u5E73\u6642\u8207\u9D3F\u5B50\u7684\u76F8\u8655\u4E0A\uFF0C\u4E00\u5B9A\u662F\u7D66\u4E88\u83AB\u5927\u7684\u5FC3\uF98A\u624D\u80FD\u63DB\uF92D\u7684\u7D50\u679C\u3002</span></p></blockquote>',8),i=[e];function p(o,l,b,_,m,f){return r(),a("div",null,i)}var k=t(s,[["render",p]]);export{g as __pageData,k as default};
